/**
 * Temporary one-shot script to safely update the AI provider key on Render.
 * Deletes itself after use. Never logs the key value.
 */
import { safeMergeRenderEnvVars, redactMergeResultForLogging } from '../services/ivx-render-env-merge';

const newKey = process.argv[2];
if (!newKey || !newKey.startsWith('vck_')) {
  console.error('Usage: bun run backend/scripts/ivx-set-ai-key.ts <vck_...>');
  process.exit(1);
}

const renderApiKey = process.env.RENDER_API_KEY || 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs';
const serviceId = process.env.RENDER_SERVICE_ID || 'srv-d7t9ivreo5us73ftose0';

const result = await safeMergeRenderEnvVars({
  renderApiKey,
  serviceId,
  updates: {
    AI_GATEWAY_API_KEY: newKey,
    OPENAI_API_KEY: newKey,
  },
  requiredKeys: [
    'AI_GATEWAY_API_KEY',
    'OPENAI_API_KEY',
    'SUPABASE_SERVICE_ROLE_KEY',
    'EXPO_PUBLIC_SUPABASE_ANON_KEY',
    'EXPO_PUBLIC_SUPABASE_URL',
    'GITHUB_TOKEN',
    'GITHUB_REPO_URL',
  ],
});

console.log(JSON.stringify(redactMergeResultForLogging(result), null, 2));
if (!result.ok) process.exit(1);

